{
  "module": "01-layout.md",
  "group": "01 — Layout & UI Components",
  "apiCount": 14,
  "apis": [
    {
      "name": "Column",
      "purpose": "垂直方向线性布局容器",
      "anchor": "column",
      "status": "found"
    },
    {
      "name": "Row",
      "purpose": "水平方向线性布局容器",
      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Stack",
      "purpose": "堆叠容器，子组件按顺序入栈叠加",
      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Text",
      "purpose": "显示文本的组件",
      "anchor": "text",
      "status": "found"
    },
    {
      "name": "Button",
      "purpose": "按钮组件，支持多种样式模式",
      "anchor": "button",
      "status": "found"
    },
    {
      "name": "Blank",
      "purpose": "空白填充组件，自动填充容器主轴剩余空间",
      "anchor": "blank",
      "status": "found"
    },
    {
      "name": "Divider",
      "purpose": "分割线组件，分隔内容块",
      "anchor": "divider",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "可滚动的容器组件",
      "anchor": "scroll",
      "status": "found"
    },
    {
      "name": "Flex",
      "purpose": "弹性布局容器组件",
      "anchor": "flex",
      "status": "found"
    },
    {
      "name": "Align/JustifyContent",
      "purpose": "子组件在容器主轴/交叉轴的对齐方式属性集",
      "anchor": "align--justifycontent--alignitems",
      "status": "found"
    },
    {
      "name": "LayoutWeight",
      "purpose": "组件布局权重，在父容器主轴按权重分配尺寸",
      "anchor": "layoutweight",
      "status": "found"
    },
    {
      "name": "Width/Height (尺寸设置)",
      "purpose": "组件自身宽度和高度的尺寸设置属性集",
      "anchor": "width--height-（尺寸设置）",
      "status": "found"
    },
    {
      "name": "backgroundColor",
      "purpose": "设置组件背景色",
      "anchor": "backgroundcolor",
      "status": "found"
    },
    {
      "name": "borderRadius",
      "purpose": "设置组件边框圆角半径",
      "anchor": "borderradius",
      "status": "found"
    }
  ],
  "notableFindings": [
    "Flex 组件存在二次布局过程，对性能敏感场景建议使用 Column/Row 替代",
    "Column/Row 未设置宽高时自动自适应子组件大小；Flex 主轴默认撑满父容器",
    "justifyContent 为 SpaceBetween / SpaceAround / SpaceEvenly 时 space 间距属性失效",
    "layoutWeight 仅在 Row/Column/Flex 父容器中生效，设置后忽略 flexShrink/flexGrow",
    "Scroll 组件的 clip 属性默认为 true",
    "backgroundColor API 18+ 支持 Optional<ResourceColor>，设为 undefined 可恢复默认透明"
  ],
  "missingApis": []
}

{
  "module": "02-animation.md",
  "group": "02 -- 3D Card Flip Animation",
  "apiCount": 8,
  "apis": [
    {
      "name": "rotate (3D旋转)",
      "purpose": "设置组件3D旋转，支持配置旋转轴向量、角度、旋转中心和视距",
      "anchor": "rotate",
      "status": "found"
    },
    {
      "name": "animation (隐式动画)",
      "purpose": "组件属性变化时自动插入渐变过渡动效",
      "anchor": "animation",
      "status": "found"
    },
    {
      "name": "animateTo (显式动画)",
      "purpose": "在闭包内改变状态时显式插入过渡动效",
      "anchor": "animatetodeprecated",
      "status": "found"
    },
    {
      "name": "transition (转场动画)",
      "purpose": "组件插入/删除时的过渡动效，支持多种效果组合",
      "anchor": "transition",
      "status": "found"
    },
    {
      "name": "opacity (透明度)",
      "purpose": "设置组件不透明度，支持子组件继承叠加",
      "anchor": "opacity",
      "status": "found"
    },
    {
      "name": "scale (缩放)",
      "purpose": "设置组件X/Y/Z轴独立缩放及缩放中心点",
      "anchor": "scale",
      "status": "found"
    },
    {
      "name": "transformCenter (变换中心点)",
      "purpose": "旋转和缩放时的变换锚点，通过centerX/centerY在RotateOptions/ScaleOptions中设置",
      "anchor": "rotateoptions对象说明",
      "status": "found"
    },
    {
      "name": "perspective (透视投影)",
      "purpose": "3D旋转视距，控制相机z轴位置以产生透视效果",
      "anchor": "rotateoptions对象说明",
      "status": "found"
    }
  ],
  "notableFindings": [
    "transformCenter和perspective不是独立组件属性，而是RotateOptions/ScaleOptions对象中的字段",
    "transition推荐使用API 10+的TransitionEffect链式API，TransitionOptions已废弃",
    "animateTo全局方法从API 18开始废弃，建议通过this.getUIContext()?.animateTo()调用",
    "3D翻转核心组合：rotate + animation/animateTo + perspective + opacity"
  ],
  "missingApis": []
}

{
  "module": "04-persistence.md",
  "group": "04 — Data Persistence & Resource Loading",
  "apiCount": 7,
  "apis": [
    {
      "name": "AppStorage",
      "purpose": "应用全局内存键值存储，与UI双向/单向绑定，支持V1(内置)和V2(AppStorageV2 from @kit.ArkUI)",
      "anchor": "appstorage-应用全局的ui状态存储",
      "status": "found"
    },
    {
      "name": "PersistentStorage",
      "purpose": "持久化存储UI状态到磁盘，与AppStorage协同工作；V2对应PersistenceV2(@kit.ArkUI)",
      "anchor": "persistentstorage-持久化存储ui状态",
      "status": "found"
    },
    {
      "name": "@ohos.data.preferences (Preferences/PreferencesKit)",
      "purpose": "轻量级键值持久化存储，不与UI绑定，需手动flush()，导入@kit.ArkData",
      "anchor": "ohosdatapreferences-用户首选项",
      "status": "found"
    },
    {
      "name": "resourceManager (getContext().resourceManager)",
      "purpose": "通过Context获取资源管理对象，读取字符串、颜色等资源及rawfile文件",
      "anchor": "resourcemanager-资源管理",
      "status": "found"
    },
    {
      "name": "rawfile (rawfile目录资源读取)",
      "purpose": "通过resourceManager.getRawFileContent(Sync)读取resources/rawfile中的文件内容",
      "anchor": "rawfile-rawfile目录资源读取",
      "status": "found"
    },
    {
      "name": "Environment (环境变量)",
      "purpose": "系统环境变量查询：V1的Environment.envProp存入AppStorage；V2的@Env装饰器直接读取系统属性(API22+)",
      "anchor": "environment-设备环境查询",
      "status": "found"
    },
    {
      "name": "@ohos.resourceManager",
      "purpose": "资源管理模块，提供字符串、rawfile等资源的读取能力，导入@kit.LocalizationKit",
      "anchor": "ohosresourcemanager-资源管理",
      "status": "found"
    }
  ],
  "notableFindings": [
    "getContext() 从 API 18 起废弃，建议使用 this.getUIContext().getHostContext()",
    "AppStorage/PersistentStorage（V1状态管理）在API 10起推荐小写新接口（link→link, PersistProp→persistProp）",
    "AppStorageV2 + PersistenceV2（@kit.ArkUI）从API 12引入，使用class + @ObservedV2/@Trace体系，取代V1的字符串键方式",
    "@Env装饰器（API 22+）基于SystemProperties枚举，用于获取窗口断点、尺寸等系统环境变量",
    "Preferences不支持进程并发安全，不能在多进程场景使用"
  ],
  "missingApis": []
}

